lua/autorun/skillforge_callbacks.lua<pre><code>-- Register a callback that gives the player health
SkillTree.RegisterCallback("My_HealOnUnlock", function(ply, treeID, skillID, rank, skillData)
    if rank == 1 then  -- Only on first unlock
        ply:SetHealth(math.min(ply:Health() + 50, ply:GetMaxHealth()))
    end
end)
</code></pre> <p>Then reference it in a tree node:</p> <pre><code>{
    "vitality_boost": {
        "name": "Vitality Boost",
        "callback": "My_HealOnUnlock",
        "effectType": "MaxHealthBonus",
        "effectValue": [10, 20, 30],
        ...
    }
}
</code></pre>

lua/skillforge/integrations/sv_lumberjack.lua<pre><code>--[[
    SkillTree Nexus - Lumberjack Integration
    Custom job: Lumberjack
]]

if not DarkRP then return end

-- Register actions
hook.Add("Initialize", "stn_lumberjack_actions", function()
    SkillTree.RegisterJobXPAction("lumberjack_chop_tree", {
        name = "Tree Chopped",
        defaultXP = 30,
        cooldown = 10,
        jobWhitelist = {"Lumberjack"}
    })
    SkillTree.RegisterJobXPAction("lumberjack_sell_wood", {
        name = "Wood Sold",
        defaultXP = 60,
        cooldown = 20,
        jobWhitelist = {"Lumberjack"}
    })
end)

-- Public API
function SkillTree.ReportTreeChopped(ply)
    SkillTree.AddJobXPByAction(ply, "lumberjack_chop_tree")
end

function SkillTree.ReportWoodSold(ply)
    SkillTree.AddJobXPByAction(ply, "lumberjack_sell_wood")
end
</code></pre> <p>Then configure the job:</p> <pre><code>SkillTree.Config.JobTreesByName["Lumberjack"] = "lumberjack_tree"
SkillTree.Config.JobXP["Lumberjack"] = {
    ChopTree = { Enabled = true, XP = 30, Cooldown = 10 },
    SellWood = { Enabled = true, XP = 60, Cooldown = 20 }
}
</code></pre>

lua/autorun/skillforge_job_actions.lua<pre><code>hook.Add("Initialize", "RegisterMyActions", function()
    -- Register a mining action for a "Miner" job
    SkillTree.RegisterJobXPAction("miner_mine_ore", {
        name = "Ore Mined",
        defaultXP = 30,
        xpPerUnit = 5,
        unitName = "ore",
        cooldown = 5,
        maxXPPerMinute = 400,
        jobWhitelist = {"Miner"}
    })

    -- Register a delivery action
    SkillTree.RegisterJobXPAction("miner_delivery", {
        name = "Ore Delivery",
        defaultXP = 100,
        cooldown = 60,
        jobWhitelist = {"Miner"}
    })
end)

-- Give XP when mining
function MineOre(ply, amount)
    -- Your mining logic
    SkillTree.AddJobXPByAction(ply, "miner_mine_ore", {
        units = amount
    })
end

-- Give XP on delivery
function DeliverOre(ply)
    SkillTree.AddJobXPByAction(ply, "miner_delivery")
end
</code></pre>

